# API HANDLERS
# ═══════════════════════════════════════════════════════════════
def api_dashboard_stats():
    db = get_db()
    # ── Evacuees KPIs: only operationally KW→PK records ──
    EV_BASE = "FROM evacuees WHERE dup_flag='CLEAR' AND (effective_route = 'kw_to_pk' OR effective_route IS NULL)"
    EV_ALL  = "FROM evacuees WHERE (effective_route = 'kw_to_pk' OR effective_route IS NULL)"

    total_all = db.execute(f"SELECT COUNT(*) c {EV_ALL}").fetchone()['c']
    total = db.execute(f"SELECT COUNT(*) c {EV_BASE}").fetchone()['c']
    departed = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND travel_status='Departed'").fetchone()['c']
    visa_obtained = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND travel_status='Visa Obtained'").fetchone()['c']
    pending = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND travel_status='Pending'").fetchone()['c']
    visa_approved = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND visa_status='Approved'").fetchone()['c']
    iraq_entries = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND country='Iraq'").fetchone()['c']
    returned = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND travel_status='Returned'").fetchone()['c']

    # Today's live counts
    departed_today = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND travel_status='Departed' AND departure_date=date('now')").fetchone()['c']
    entered_today = departed_today
    returned_today = db.execute(f"SELECT COUNT(*) c {EV_BASE} AND travel_status='Returned' AND departure_date=date('now')").fetchone()['c']

    # Pre-database Jazeera Airways passengers
    jazeera_departed = 120

    by_country = [dict(r) for r in db.execute(f"""
        SELECT country, COUNT(*) total,
        SUM(CASE WHEN travel_status='Departed' THEN 1 ELSE 0 END) departed,
        SUM(CASE WHEN travel_status='Visa Obtained' THEN 1 ELSE 0 END) visa_obtained,
        SUM(CASE WHEN travel_status='Pending' THEN 1 ELSE 0 END) pending,
        SUM(CASE WHEN gender='Male' THEN 1 ELSE 0 END) males,
        SUM(CASE WHEN gender='Female' THEN 1 ELSE 0 END) females,
        SUM(CASE WHEN gender='Child' THEN 1 ELSE 0 END) children
        {EV_ALL} GROUP BY country ORDER BY COUNT(*) DESC
    """).fetchall()]

    by_gender = [dict(r) for r in db.execute(f"""
        SELECT gender, COUNT(*) count,
        SUM(CASE WHEN travel_status='Departed' THEN 1 ELSE 0 END) departed
        {EV_ALL} GROUP BY gender
    """).fetchall()]

    by_date = [dict(r) for r in db.execute(f"""
        SELECT date_of_request date, COUNT(*) new_requests,
        SUM(CASE WHEN travel_status='Departed' THEN 1 ELSE 0 END) departed,
        SUM(CASE WHEN travel_status='Visa Obtained' THEN 1 ELSE 0 END) visa_obtained,
        SUM(CASE WHEN travel_status='Pending' THEN 1 ELSE 0 END) pending
        {EV_ALL} AND date_of_request IS NOT NULL AND date_of_request != ''
        GROUP BY date_of_request ORDER BY date_of_request
    """).fetchall()]

    by_visa = [dict(r) for r in db.execute(f"SELECT COALESCE(visa_status,'Not Set') status, COUNT(*) count {EV_ALL} GROUP BY visa_status").fetchall()]
    by_border = [dict(r) for r in db.execute(f"SELECT border_crossing, COUNT(*) count {EV_ALL} AND border_crossing != '' GROUP BY border_crossing").fetchall()]

    duplicates = db.execute("SELECT COUNT(*) c FROM evacuees WHERE dup_flag='DUPLICATE' AND (effective_route = 'kw_to_pk' OR effective_route IS NULL)").fetchone()['c']

    # ── Route mismatch summary for dashboard ──
    mismatch_total = db.execute("SELECT COUNT(*) c FROM evacuees WHERE route_mismatch = 1").fetchone()['c']
    mismatch_pending_review = db.execute("SELECT COUNT(*) c FROM evacuees WHERE review_status IN ('pending','under_review','needs_followup')").fetchone()['c']
    corrected_to_pk = db.execute("SELECT COUNT(*) c FROM evacuees WHERE effective_route = 'pk_to_kw' AND route_mismatch = 1").fetchone()['c']

    db.close()
    return {
        'kpi': {'total': total, 'total_all': total_all, 'departed': departed, 'visa_obtained': visa_obtained, 'pending': pending,
                'visa_approved': visa_approved, 'iraq_entries': iraq_entries, 'duplicates': duplicates,
                'departed_today': departed_today, 'entered_today': entered_today,
                'returned': returned, 'returned_today': returned_today,
                'jazeera_departed': jazeera_departed,
                'mismatch_total': mismatch_total, 'mismatch_pending_review': mismatch_pending_review,
                'corrected_to_pk': corrected_to_pk},
        'by_country': by_country, 'by_gender': by_gender, 'by_date': by_date,
        'by_visa': by_visa, 'by_border': by_border
    }

def api_records(params):
    db = get_db()
    where = ["1=1"]
    qparams = []
    if params.get('search'):
        search_val = params['search'].strip()
        tracking_match = re.match(r'^PKE-?(\d+)$', search_val, re.IGNORECASE)
        if tracking_match:
            rec_id = int(tracking_match.group(1))
            where.append("id = ?")
            qparams.append(rec_id)
        else:
            s = f"%{search_val}%"
            where.append("(name LIKE ? OR passport LIKE ? OR cnic LIKE ? OR mobile LIKE ? OR civil_id LIKE ?)")
            qparams.extend([s, s, s, s, s])
    if params.get('status'):
        where.append("travel_status = ?")
        qparams.append(params['status'])
    if params.get('country'):
        where.append("country = ?")
        qparams.append(params['country'])
    if params.get('gender'):
        where.append("gender = ?")
        qparams.append(params['gender'])
    if params.get('visa'):
        where.append("visa_status = ?")
        qparams.append(params['visa'])
    if params.get('dup'):
        where.append("dup_flag = ?")
        qparams.append(params['dup'])
    # ── Route mismatch filters ──
    if params.get('effective_route'):
        where.append("effective_route = ?")
        qparams.append(params['effective_route'])
    if params.get('route_mismatch') == '1':
        where.append("route_mismatch = 1")
    elif params.get('route_mismatch') == '0':
        where.append("(route_mismatch = 0 OR route_mismatch IS NULL)")
    if params.get('hide_mismatch') == '1':
        where.append("(route_mismatch = 0 OR route_mismatch IS NULL)")
    if params.get('location_review_flag') == '1':
        where.append("location_review_flag = 1")
    if params.get('current_country'):
        where.append("current_country = ?")
        qparams.append(params['current_country'])
    if params.get('ip_location_status'):
        where.append("ip_location_status = ?")
        qparams.append(params['ip_location_status'])

    rows = db.execute(f"SELECT * FROM evacuees WHERE {' AND '.join(where)} ORDER BY id DESC", qparams).fetchall()
    result = [dict(r) for r in rows]
    db.close()
    return result

def api_returnees(params):
    db = get_db()
    where = ["ci.cancellation_status = 'active'"]
    qparams = []

    if params.get('search'):
        s = f"%{params['search'].strip()}%"
        where.append("""(
            pm.full_name LIKE ? OR
            pm.passport LIKE ? OR
            ci.reference_number LIKE ? OR
            pm.mobile LIKE ? OR
            pm.whatsapp LIKE ?
        )""")
        qparams.extend([s, s, s, s, s])

    if params.get('status'):
        where.append("ci.status = ?")
        qparams.append(params['status'])

    if params.get('province'):
        where.append("ci.province_pk = ?")
        qparams.append(params['province'])

    if params.get('urgency'):
        where.append("ci.travel_urgency = ?")
        qparams.append(params['urgency'])

    if params.get('visa'):
        if params['visa'] == 'approved':
            where.append("ci.saudi_visa_approved = 'yes'")
        elif params['visa'] == 'pending':
            where.append("(ci.saudi_visa_approved = 'pending' OR ci.saudi_visa_approved = '' OR ci.saudi_visa_approved IS NULL)")
        elif params['visa'] == 'not_applied':
            where.append("(ci.saudi_visa_applied = 'no' OR ci.saudi_visa_applied = '' OR ci.saudi_visa_applied IS NULL)")

    rows = db.execute(f"""
        SELECT
            ci.id,
            ci.reference_number,
            ci.status,
            ci.travel_direction,
            ci.current_city_pk,
            ci.province_pk,
            ci.destination_area_kw,
            ci.travel_urgency,
            ci.travel_readiness,
            ci.traveling_alone,
            ci.group_size,
            ci.adults_count,
            ci.children_count,
            ci.infants_count,
            ci.interest_level,
            ci.saudi_visa_applied,
            ci.saudi_visa_approved,
            ci.dup_flag,
            ci.is_moh_employee,
            ci.moh_leave_end,
            ci.submission_timestamp,
            pm.full_name,
            pm.passport,
            pm.mobile,
            pm.whatsapp,
            pm.gender
        FROM charter_interest ci
        JOIN person_master pm ON pm.id = ci.person_id
        WHERE {" AND ".join(where)}
        ORDER BY ci.id DESC
    """, qparams).fetchall()

    db.close()
    return [dict(r) for r in rows]

def api_returnees_stats():
    db = get_db()

    total = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active'
    """).fetchone()['c']

    submitted = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active' AND status = 'Submitted'
    """).fetchone()['c']

    verified = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active' AND verification_status = 'verified'
    """).fetchone()['c']

    contacted = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active' AND followup_status = 'contacted'
    """).fetchone()['c']

    approved_visa = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active' AND saudi_visa_approved = 'yes'
    """).fetchone()['c']

    pending_visa = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active' AND (
            saudi_visa_approved = 'pending' OR
            saudi_visa_approved = '' OR
            saudi_visa_approved IS NULL
        )
    """).fetchone()['c']

    with_family = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active' AND traveling_alone = 'no'
    """).fetchone()['c']

    ready_to_travel = db.execute("""
        SELECT COUNT(*) c
        FROM charter_interest
        WHERE cancellation_status = 'active'
          AND interest_level IN ('likely', 'ready')
    """).fetchone()['c']

    by_status = [dict(r) for r in db.execute("""
        SELECT status, COUNT(*) count
        FROM charter_interest
        WHERE cancellation_status = 'active'
        GROUP BY status
        ORDER BY count DESC
    """).fetchall()]

    by_province = [dict(r) for r in db.execute("""
        SELECT COALESCE(province_pk, 'Unknown') province, COUNT(*) count
        FROM charter_interest
        WHERE cancellation_status = 'active'
        GROUP BY province_pk
        ORDER BY count DESC
    """).fetchall()]

    by_urgency = [dict(r) for r in db.execute("""
        SELECT COALESCE(travel_urgency, 'general') urgency, COUNT(*) count
        FROM charter_interest
        WHERE cancellation_status = 'active'
        GROUP BY travel_urgency
        ORDER BY count DESC
    """).fetchall()]

    # ── Corrected evacuees now operationally PK→KW ──
    corrected_from_evacuees = db.execute("""
        SELECT COUNT(*) c FROM evacuees
        WHERE effective_route = 'pk_to_kw' AND route_mismatch = 1
    """).fetchone()['c']

    db.close()

    return {
        'kpi': {
            'total': total,
            'submitted': submitted,
            'verified': verified,
            'contacted': contacted,
            'approved_visa': approved_visa,
            'pending_visa': pending_visa,
            'with_family': with_family,
            'ready_to_travel': ready_to_travel,
            'corrected_from_evacuees': corrected_from_evacuees
        },
        'by_status': by_status,
        'by_province': by_province,
        'by_urgency': by_urgency
    }

def normalize_border(val):
    if not val: return val
    v = val.strip().lower()
    if 'khafji' in v or 'khafi' in v: return 'Khafji Border'
    if 'salmi' in v or 'salmy' in v: return 'Salmi Border'
    return val

def api_save_record(data, user):
    if data.get('border_crossing'):
        data['border_crossing'] = normalize_border(data['border_crossing'])
    db = get_db()
    rec_id = data.get('id')
    fields = ['name','passport','cnic','gender','country','civil_id','border_crossing',
              'mobile','company','visa_status','travel_status','airline','ticket_number',
              'departure_airport','destination_country','date_of_request','email',
              'dob','emergency_contact','medical','family_group_id','dependents',
              'accommodation','priority','remarks','planned_departure','saudi_city',
              'traveling_with_family','confirm_ksa_3days','departure_date',
              'current_country','current_city_pakistan','current_area_kuwait']

    if rec_id:  # Update
        # Get old record to detect changes
        old_rec = dict(db.execute("SELECT * FROM evacuees WHERE id = ?", [rec_id]).fetchone())

        # ── Only update fields actually present in the incoming data ──
        # This prevents blanking out fields not included in the request
        # (e.g. viewSave sends ~30 fields but the full list has 33+)
        update_fields = [f for f in fields if f in data]

        # ── Record Locking: prevent edits to core fields if locked ──
        LOCKED_FIELDS = {'name','passport','cnic','gender','country','civil_id',
                         'visa_status','travel_status','mofa_status','dob',
                         'border_crossing','departure_airport','destination_country'}
        if old_rec.get('record_locked') == 1 or old_rec.get('record_locked') == '1':
            # Only check fields actually being submitted, not all fields
            changed_locked = [f for f in LOCKED_FIELDS if f in data and str(data.get(f, '')) != str(old_rec.get(f, ''))]
            if changed_locked:
                db.close()
                return {'success': False, 'error': f'Record is locked (sent to MOFA KSA). Cannot edit: {", ".join(changed_locked)}'}

        sets = [f"{f} = ?" for f in update_fields]
        vals = [data.get(f, '') for f in update_fields]

        # Build a merged view of old + new data for duplicate checking
        merged_data = {f: old_rec.get(f, '') for f in fields}
        merged_data.update({f: data[f] for f in update_fields})

        dup_flags = check_duplicates(db, merged_data, exclude_id=rec_id)
        dup_flag = 'DUPLICATE' if dup_flags else 'CLEAR'
        sets.append("dup_flag = ?"); vals.append(dup_flag)
        sets.append("updated_at = CURRENT_TIMESTAMP")
        sets.append("updated_by = ?"); vals.append(user)
        vals.append(rec_id)
        db.execute(f"UPDATE evacuees SET {', '.join(sets)} WHERE id = ?", vals)
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('update', ?, ?, ?)",
                   (rec_id, user, json.dumps(data)))

        # Apply workflow rules only for fields actually sent and changed
        workflow_changes = []
        for field in ['visa_status', 'ticket_number']:
            if field in data:
                old_val = old_rec.get(field, '')
                new_val = data.get(field, '')
                if old_val != new_val:
                    wf = apply_workflow_rules(db, rec_id, field, new_val, user)
                    workflow_changes.extend(wf)

        # Auto-email when visa status transitions to Approved
        if 'visa_status' in data and old_rec.get('visa_status') != 'Approved' and data.get('visa_status') == 'Approved':
            updated = dict(db.execute("SELECT id, name, passport, email FROM evacuees WHERE id = ?", [rec_id]).fetchone())
            _queue_visa_approved_email(updated, user)

        db.commit(); db.close()
        return {'success': True, 'id': rec_id, 'dup_flag': dup_flag, 'dup_details': dup_flags, 'workflow': workflow_changes}
    else:  # Insert
        if not data.get('date_of_request'):
            data['date_of_request'] = datetime.now().strftime('%Y-%m-%d')
        dup_flags = check_duplicates(db, data)
        dup_flag = 'DUPLICATE' if dup_flags else 'CLEAR'
        vals = [data.get(f, '') for f in fields] + [dup_flag]
        placeholders = ', '.join(['?'] * (len(fields) + 1))
        cur = db.execute(f"INSERT INTO evacuees ({', '.join(fields)}, dup_flag) VALUES ({placeholders})", vals)
        new_id = cur.lastrowid
        new_rec = dict(db.execute("SELECT id, name, passport, email FROM evacuees WHERE id = ?", [new_id]).fetchone())
        _queue_registration_email(new_rec, user)
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('create', ?, ?, ?)",
                   (new_id, user, json.dumps(data)))
        db.commit(); db.close()
        return {'success': True, 'id': new_id, 'dup_flag': dup_flag, 'dup_details': dup_flags}

# ═══════════════════════════════════════════════════════════════
# TRAVEL FACILITATION — PERSON MASTER & CHARTER INTEREST LOGIC
# ═══════════════════════════════════════════════════════════════

def _normalize_passport(val):
    """Strip, uppercase, remove spaces."""
    if not val: return ''
    return re.sub(r'\s+', '', val.strip().upper())

def _normalize_cnic(val):
    """Strip dashes, spaces."""
    if not val: return ''
    return re.sub(r'[\s\-]', '', val.strip())

def _generate_charter_ref(db=None):
    """Generate a unique TFR-XXXX reference number."""
    close_after = False
    if db is None:
        db = get_db()
        close_after = True
    try:
        while True:
            num = secrets.randbelow(9000) + 1000
            ref = f'TFR-{num}'
            exists = db.execute("SELECT 1 FROM charter_interest WHERE reference_number = ?", [ref]).fetchone()
            if not exists:
                return ref
    finally:
        if close_after:
            db.close()

def find_or_create_person(db, data):
    """
    Passport-first identity resolution against person_master,
    with fallback to CNIC and Civil ID. Links to existing evacuee
    record if found. Returns person_master.id
    """
    passport = _normalize_passport(data.get('passport'))
    cnic = _normalize_cnic(data.get('cnic'))
    civil_id = (data.get('civil_id') or '').strip()
    mobile = (data.get('mobile') or '').strip()

    person = None

    # Primary match: passport
    if passport:
        person = db.execute(
            "SELECT id FROM person_master WHERE UPPER(REPLACE(passport,' ','')) = ?",
            [passport]).fetchone()

    # Secondary: CNIC
    if not person and cnic:
        person = db.execute(
            "SELECT id FROM person_master WHERE REPLACE(REPLACE(cnic,'-',''),' ','') = ?",
            [cnic]).fetchone()

    # Secondary: Civil ID
    if not person and civil_id:
        person = db.execute(
            "SELECT id FROM person_master WHERE TRIM(civil_id) = ?",
            [civil_id]).fetchone()

    if person:
        return person['id']

    # No match — create new person_master record
    # Also try to link to existing evacuees table
    evacuee_link = None
    if passport:
        ev = db.execute("SELECT id FROM evacuees WHERE UPPER(TRIM(passport)) = ?", [passport]).fetchone()
        if ev:
            evacuee_link = ev['id']
    if not evacuee_link and cnic:
        ev = db.execute("SELECT id FROM evacuees WHERE REPLACE(REPLACE(cnic,'-',''),' ','') = ?", [cnic]).fetchone()
        if ev:
            evacuee_link = ev['id']

    cur = db.execute("""
        INSERT INTO person_master
            (full_name, father_name, gender, date_of_birth, nationality,
             passport, passport_expiry, cnic, civil_id,
             mobile, whatsapp, alt_mobile, email,
             emergency_name, emergency_relation, emergency_phone,
             evacuee_link_id, created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?, CURRENT_TIMESTAMP)
    """, [
        data.get('name') or data.get('full_name') or '',
        data.get('father_name', ''),
        data.get('gender', ''),
        data.get('dob') or data.get('date_of_birth', ''),
        data.get('nationality', 'Pakistani'),
        passport,
        data.get('passport_expiry', ''),
        cnic,
        civil_id,
        mobile,
        data.get('whatsapp', ''),
        data.get('alt_mobile', ''),
        data.get('email', ''),
        data.get('emergency_name', ''),
        data.get('emergency_relation', ''),
        data.get('emergency_phone', ''),
        evacuee_link
    ])
    return cur.lastrowid


def api_charter_register(data, source_ip='unknown'):
    """
    Public-facing charter/travel interest registration.
    1) Validates required fields
    2) Resolves or creates person_master record (with evacuee linkage)
    3) Checks for duplicate charter_interest by same person+direction
    4) Inserts charter_interest row
    5) Optionally inserts family_group + family_members
    6) Optionally inserts cargo_interest
    7) Returns reference number
    """
    # Required field validation
    name = (data.get('name') or data.get('full_name') or '').strip()
    passport = _normalize_passport(data.get('passport'))
    mobile = (data.get('mobile') or '').strip()
    direction = data.get('travel_direction', 'kw_to_pk')

    if not name or not passport or not mobile:
        return {'success': False, 'error': 'Full name, passport number, and mobile number are required.'}

    if direction not in ('kw_to_pk', 'pk_to_kw', 'both'):
        direction = 'kw_to_pk'

    db = get_db()

    # Rate limiting: max 10 submissions per IP per hour
    one_hour_ago = (datetime.now() - timedelta(hours=1)).strftime('%Y-%m-%d %H:%M:%S')
    recent = db.execute(
        "SELECT COUNT(*) c FROM audit_log WHERE user = ? AND action = 'charter_register' AND created_at > ?",
        [source_ip, one_hour_ago]).fetchone()['c']
    if recent >= 10:
        db.close()
        return {'success': False, 'error': 'Too many submissions from this device. Please try again later.'}

    # Resolve identity
    person_id = find_or_create_person(db, data)

    # Check for existing active charter_interest for same person + direction
    existing = db.execute(
        "SELECT id, reference_number, status, source_channel FROM charter_interest WHERE person_id = ? AND travel_direction = ? AND cancellation_status = 'active'",
        [person_id, direction]).fetchone()

    if existing:
        existing = dict(existing)
        ci_id = existing['id']
        ref = existing['reference_number']

        # UPDATE person_master with richer data (only fill empty or update with new non-empty values)
        pm_fields = ['full_name','father_name','gender','date_of_birth','passport_expiry',
                     'cnic','civil_id','mobile','whatsapp','alt_mobile','email',
                     'emergency_name','emergency_relation','emergency_phone']
        pm_map = {'full_name': data.get('name') or data.get('full_name',''),
                  'father_name': data.get('father_name',''),
                  'gender': data.get('gender',''),
                  'date_of_birth': data.get('dob') or data.get('date_of_birth',''),
                  'passport_expiry': data.get('passport_expiry',''),
                  'cnic': _normalize_cnic(data.get('cnic','')),
                  'civil_id': (data.get('civil_id') or '').strip(),
                  'mobile': (data.get('mobile') or '').strip(),
                  'whatsapp': data.get('whatsapp',''),
                  'alt_mobile': data.get('alt_mobile',''),
                  'email': data.get('email',''),
                  'emergency_name': data.get('emergency_name',''),
                  'emergency_relation': data.get('emergency_relation',''),
                  'emergency_phone': data.get('emergency_phone','')}
        pm_updates, pm_params = [], []
        for f in pm_fields:
            new_val = pm_map.get(f, '').strip() if pm_map.get(f) else ''
            if new_val:
                # Update: overwrite with latest non-empty value
                pm_updates.append(f"{f} = ?")
                pm_params.append(new_val)
        if pm_updates:
            pm_params.append(person_id)
            db.execute(f"UPDATE person_master SET {', '.join(pm_updates)}, updated_at = CURRENT_TIMESTAMP WHERE id = ?", pm_params)

        # UPDATE charter_interest with all new detailed fields (overwrite with non-empty)
        ci_update_fields = {
            'current_area_kuwait': data.get('current_area_kuwait', ''),
            'residency_status': data.get('residency_status', ''),
            'destination_city_pk': data.get('destination_city_pk', ''),
            'preferred_airport_pk': data.get('preferred_airport_pk', ''),
            'current_city_pk': data.get('current_city_pk', ''),
            'province_pk': data.get('province_pk', ''),
            'has_valid_civil_id': data.get('has_valid_civil_id', ''),
            'has_valid_residency': data.get('has_valid_residency', ''),
            'saudi_visa_applied': data.get('saudi_visa_applied', ''),
            'saudi_visa_approved': data.get('saudi_visa_approved', ''),
            'employer_kw': data.get('employer_kw', ''),
            'destination_area_kw': data.get('destination_area_kw', ''),
            'travel_urgency': data.get('travel_urgency', ''),
            'earliest_travel_date': data.get('earliest_travel_date', ''),
            'latest_travel_date': data.get('latest_travel_date', ''),
            'travel_readiness': data.get('travel_readiness', ''),
            'traveling_alone': data.get('traveling_alone', ''),
            'group_size': data.get('group_size', ''),
            'adults_count': data.get('adults_count', ''),
            'children_count': data.get('children_count', ''),
            'infants_count': data.get('infants_count', ''),
            'must_travel_together': data.get('must_travel_together', ''),
            'interest_level': data.get('interest_level', ''),
            'can_bear_cost': data.get('can_bear_cost', ''),
            'max_affordable_fare': data.get('max_affordable_fare', ''),
            'fare_currency': data.get('fare_currency', ''),
            'deposit_ready': data.get('deposit_ready', ''),
            'max_deposit_amount': data.get('max_deposit_amount', ''),
            'preferred_payment': data.get('preferred_payment', ''),
            'employer_sponsor': data.get('employer_sponsor', ''),
            'employer_name': data.get('employer_name', ''),
            'needs_installment': data.get('needs_installment', ''),
            'flexible_date': data.get('flexible_date', ''),
            'flexible_airport': data.get('flexible_airport', ''),
            'flexible_boarding': data.get('flexible_boarding', ''),
            'flexible_charter_vs_scheduled': data.get('flexible_charter_vs_scheduled', ''),
            'flexible_baggage': data.get('flexible_baggage', ''),
            'extra_baggage': data.get('extra_baggage', ''),
            'extra_baggage_kg': data.get('extra_baggage_kg', ''),
            'is_moh_employee': data.get('is_moh_employee', ''),
            'moh_leave_end': data.get('moh_leave_end', ''),
        }
        ci_ups, ci_ps = [], []
        for f, v in ci_update_fields.items():
            sv = str(v).strip() if v else ''
            if sv:
                ci_ups.append(f"{f} = ?")
                ci_ps.append(sv)
        if ci_ups:
            # Mark as updated via web (richer data now)
            ci_ups.append("source_channel = ?")
            ci_ps.append('web_update')
            ci_ps.append(ci_id)
            db.execute(f"UPDATE charter_interest SET {', '.join(ci_ups)}, updated_at = CURRENT_TIMESTAMP WHERE id = ?", ci_ps)

        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('charter_update_via_form', ?, ?, ?)",
                   (ci_id, source_ip, json.dumps({'name': name, 'passport': passport, 'updated_fields': len(ci_ups)})))
        db.commit()
        db.close()
        return {
            'success': True,
            'updated': True,
            'reference_number': ref,
            'id': ci_id,
            'person_id': person_id,
            'message': f'Your registration {ref} has been updated with the latest information.'
        }

    # Generate reference
    ref = _generate_charter_ref(db)

    # Insert charter_interest
    ci_fields = {
        'person_id': person_id,
        'reference_number': ref,
        'travel_direction': direction,
        'current_area_kuwait': data.get('current_area_kuwait', ''),
        'residency_status': data.get('residency_status', ''),
        'destination_city_pk': data.get('destination_city_pk', ''),
        'preferred_airport_pk': data.get('preferred_airport_pk', ''),
        'current_city_pk': data.get('current_city_pk', ''),
        'province_pk': data.get('province_pk', ''),
        'has_valid_civil_id': data.get('has_valid_civil_id', ''),
        'has_valid_residency': data.get('has_valid_residency', ''),
        'saudi_visa_applied': data.get('saudi_visa_applied', ''),
        'saudi_visa_approved': data.get('saudi_visa_approved', ''),
        'employer_kw': data.get('employer_kw', ''),
        'destination_area_kw': data.get('destination_area_kw', ''),
        'travel_urgency': data.get('travel_urgency', 'general'),
        'earliest_travel_date': data.get('earliest_travel_date', ''),
        'latest_travel_date': data.get('latest_travel_date', ''),
        'travel_readiness': data.get('travel_readiness', 'flexible'),
        'traveling_alone': data.get('traveling_alone', 'yes'),
        'group_size': int(data.get('group_size', 1) or 1),
        'adults_count': int(data.get('adults_count', 1) or 1),
        'children_count': int(data.get('children_count', 0) or 0),
        'infants_count': int(data.get('infants_count', 0) or 0),
        'must_travel_together': data.get('must_travel_together', 'yes'),
        'interest_level': data.get('interest_level', 'registering_interest'),
        'can_bear_cost': data.get('can_bear_cost', ''),
        'max_affordable_fare': float(data.get('max_affordable_fare', 0) or 0),
        'fare_currency': data.get('fare_currency', 'KWD'),
        'deposit_ready': data.get('deposit_ready', ''),
        'max_deposit_amount': float(data.get('max_deposit_amount', 0) or 0),
        'preferred_payment': data.get('preferred_payment', ''),
        'employer_sponsor': data.get('employer_sponsor', ''),
        'employer_name': data.get('employer_name', ''),
        'needs_installment': data.get('needs_installment', ''),
        'flexible_date': data.get('flexible_date', 'yes'),
        'flexible_airport': data.get('flexible_airport', 'yes'),
        'flexible_boarding': data.get('flexible_boarding', 'yes'),
        'flexible_charter_vs_scheduled': data.get('flexible_charter_vs_scheduled', 'yes'),
        'flexible_baggage': data.get('flexible_baggage', 'yes'),
        'extra_baggage': data.get('extra_baggage', 'no'),
        'extra_baggage_kg': float(data.get('extra_baggage_kg', 0) or 0),
        'source_channel': data.get('source_channel', 'web'),
        'is_moh_employee': data.get('is_moh_employee', 'no'),
        'moh_leave_end': data.get('moh_leave_end', ''),
        'status': 'Submitted'
    }

    cols = list(ci_fields.keys())
    vals = [ci_fields[c] for c in cols]
    placeholders = ', '.join(['?'] * len(cols))
    cur = db.execute(f"INSERT INTO charter_interest ({', '.join(cols)}) VALUES ({placeholders})", vals)
    ci_id = cur.lastrowid

    # Family members (if group)
    if ci_fields['traveling_alone'] == 'no' and data.get('family_members'):
        fg_cur = db.execute(
            "INSERT INTO family_group (charter_interest_id, group_label, total_members) VALUES (?, ?, ?)",
            [ci_id, f"{name} family", ci_fields['group_size']])
        fg_id = fg_cur.lastrowid
        for mem in data['family_members']:
            if isinstance(mem, dict) and mem.get('full_name'):
                db.execute(
                    "INSERT INTO family_members (family_group_id, full_name, passport, gender, date_of_birth, relationship) VALUES (?,?,?,?,?,?)",
                    [fg_id, mem.get('full_name',''), _normalize_passport(mem.get('passport','')),
                     mem.get('gender',''), mem.get('date_of_birth',''), mem.get('relationship','')])

    # Cargo interest (optional)
    if data.get('has_cargo') == 'yes' and data.get('cargo_type'):
        db.execute("""
            INSERT INTO cargo_interest
                (person_id, business_name, cargo_type, estimated_volume,
                 estimated_weight_kg, origin_city, destination,
                 special_handling, special_handling_desc)
            VALUES (?,?,?,?,?,?,?,?,?)
        """, [person_id, data.get('business_name',''), data.get('cargo_type',''),
              data.get('estimated_volume',''), float(data.get('estimated_weight_kg',0) or 0),
              data.get('origin_city',''), data.get('cargo_destination',''),
              data.get('special_handling','no'), data.get('special_handling_desc','')])

    # Audit log
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('charter_register', ?, ?, ?)",
               (ci_id, source_ip, json.dumps({'name': name, 'passport': passport, 'direction': direction, 'ref': ref})))
    db.commit()
    db.close()

    return {
        'success': True,
        'reference_number': ref,
        'id': ci_id,
        'person_id': person_id
    }


def api_charter_status_lookup(ref_or_passport):
    """
    Public status lookup by reference number (TFR-XXXX) or passport.
    Returns only safe, non-admin fields.
    """
    val = (ref_or_passport or '').strip().upper()
    if not val:
        return {'success': False, 'error': 'Please enter your reference number or passport number.'}

    db = get_db()
    row = None

    if val.startswith('TFR-'):
        row = db.execute("""
            SELECT ci.reference_number, ci.status, ci.travel_direction,
                   ci.submission_timestamp, pm.full_name
            FROM charter_interest ci
            JOIN person_master pm ON pm.id = ci.person_id
            WHERE ci.reference_number = ? AND ci.cancellation_status = 'active'
        """, [val]).fetchone()
    else:
        row = db.execute("""
            SELECT ci.reference_number, ci.status, ci.travel_direction,
                   ci.submission_timestamp, pm.full_name
            FROM charter_interest ci
            JOIN person_master pm ON pm.id = ci.person_id
            WHERE UPPER(REPLACE(pm.passport,' ','')) = ? AND ci.cancellation_status = 'active'
            ORDER BY ci.created_at DESC LIMIT 1
        """, [val]).fetchone()

    db.close()

    if not row:
        return {'success': False, 'error': 'No active registration found. Please check your reference number or passport number.'}

    row = dict(row)
    return {
        'success': True,
        'reference_number': row['reference_number'],
        'name': row['full_name'],
        'status': row['status'],
        'direction': row['travel_direction'],
        'submitted': row['submission_timestamp']
    }


